import React, { useState } from 'react';
import { Box } from 'ink';
import { Select } from './selection/Select.js';
import { ProgressBar } from './feedback/ProgressBar.js';
import { Spinner } from './feedback/Spinner.js';
import { Alert } from './feedback/Alert.js';

type Step = 'env' | 'deploying' | 'done';

export function DeployWizardRecipe() {
  const [step, setStep] = useState<Step>('env');
  const [progress, setProgress] = useState(0);

  return (
    <Box flexDirection="column" gap={1}>
      {step === 'env' && (
        <Select
          label="Select environment:"
          options={[
            { value: 'staging', label: 'Staging' },
            { value: 'production', label: 'Production' },
          ]}
          onSubmit={() => setStep('deploying')}
        />
      )}
      {step === 'deploying' && (
        <Box flexDirection="column" gap={1}>
          <Spinner label="Deploying..." />
          <ProgressBar value={progress} total={100} label="Deploy progress" />
        </Box>
      )}
      {step === 'done' && (
        <Alert variant="success" title="Deployed!">Your app is live.</Alert>
      )}
    </Box>
  );
}
